INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1113, 187539, 9, 3, '范巴斯滕', '昨天，天下足球的绝对巨星放的是巴斯滕。看的俺激动得鸡皮疙瘩落了一地。巴斯滕踢球还不是一般的优雅。长1米9多的个子，作为一个前锋，面对意甲那么多凶狠的后卫，还能踢得如此从容和优雅，简直就是天才嘛。当今足坛在踢球的齐达内的风格算是优雅派的王者了吧，不过他踢的是中场，面对的直接对抗不会比前锋和后卫之间的激烈。而且秃头有时候传球的姿势很笨拙，看上去很硬。再回想一下当年的巴斯滕，真是天妒英才啊。昨天放的巴斯滕的那些进球，有倒挂的，有88欧锦赛的0度脚凌空抽射的，有92(?)丰田杯上的挑射的，有意甲上脚后跟反挑射门的，头球，远射，抢点等等等等，令人叹为观止。靠，再感慨一下，天妒英才啊。', '昨天，天下足球的绝对巨星放的是巴斯滕。看的俺激动得鸡皮疙瘩落了一地。巴斯滕踢球还不是一般的优雅。长1米9多的个子，作为一个前锋，面对意甲那么多凶狠的后卫，还能踢得如此从容和优雅，简直就是天才嘛。当今足坛在踢球的齐达内的风格算是优雅派的王者了吧，不过他踢的是中场，面对的直接对抗不会比前锋和后卫之间的激烈。而且秃头有时候传球的姿势很笨拙，看上去很硬。再回想一下当年的巴斯滕，真是天妒英才啊。昨天放的巴斯滕的那些进球，有倒挂的，有88欧锦赛的0度脚凌空抽射的，有92(?)丰田杯上的挑射的，有意甲上脚后跟反挑射门的，头球，远射，抢点等等等等，令人叹为观止。靠，再感慨一下，天妒英才啊。', NULL, '2002-10-29 09:39:00', 10, '20021128030741_bbsid_187539_board_9_6936800fc3.html', '20021128030741');
